const items = $input.all();

// Busca borrador activo del usuario
const borrador = items.find(i => i.json.estado === 'Borrador');
if (borrador) return [{ json: borrador.json }];

// Si no hay borrador, checa si el texto del usuario parece un ID de ticket
const texto = $('Telegram Trigger').item.json.message.text?.trim().toUpperCase() || '';
const esTKT = /^TKT-\d+$/.test(texto);

if (esTKT) {
  // Simula un "estado" para que Estado Flujo sepa que hay que buscar ese ticket
  return [{ json: { estado: 'ConsultandoEstado' } }];
}

// Sin sesión activa ni ID → ir al menú
return [{ json: {} }];

const todos = $input.all()
  .map(i => i.json)
  .filter(i => i.id_ticket && i.id_ticket.startsWith('TKT-'))
  .sort((a, b) => Number(a.row_number) - Number(b.row_number));

const actualizaciones = todos
  .map((t, index) => {
    const posDesdeUltimo = todos.length - 1 - index;
    let estadoNuevo;
    if (posDesdeUltimo === 0) estadoNuevo = 'Abierto';
    else if (posDesdeUltimo === 1) estadoNuevo = 'En proceso';
    else estadoNuevo = 'Cerrado';
    return { id_ticket: t.id_ticket, estado: estadoNuevo, row_number: t.row_number };
  })
  .filter((t, index) => t.estado !== todos[index].estado);

if (actualizaciones.length === 0) {
  return [{ json: { nada_que_actualizar: true }, pairedItem: { item: 0 } }];
}

return actualizaciones.map(t => ({
  json: t,
  pairedItem: { item: 0 }   // <-- esto es lo que soluciona el error
}));
